'use client';

import JSZip from 'jszip';
import type { UnitConfig, MAData, BriefData } from './types';

const TEMPLATE_B64 = ``;

function b64ToArrayBuffer(b64: string): ArrayBuffer {
  const bin = atob(b64);
  const buf = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
  return buf.buffer;
}

function escXml(s: string): string {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

function replaceAll(xml: string, from: string, to: string): string {
  const esc = escXml(from);
  return xml.split(esc).join(escXml(to));
}

function replaceFirst(xml: string, from: string, to: string): string {
  const esc = escXml(from);
  const idx = xml.indexOf(esc);
  if (idx < 0) return xml;
  return xml.slice(0, idx) + escXml(to) + xml.slice(idx + esc.length);
}

function textToRuns(text: string): string {
  return text.split('\n').map((line, i) =>
    i === 0
      ? `<w:r><w:t xml:space="preserve">${escXml(line)}</w:t></w:r>`
      : `<w:r><w:br/><w:t xml:space="preserve">${escXml(line)}</w:t></w:r>`
  ).join('');
}

export async function generateDocx(
  unit: UnitConfig, ma: MAData, brief: BriefData
): Promise<void> {
  const zip = await JSZip.loadAsync(b64ToArrayBuffer(TEMPLATE_B64));
  let docXml = await zip.file('word/document.xml')!.async('string');

  // replaceAll-Ersetzungen
  docXml = replaceAll(docXml, 'DRK-Musterverband', unit.nameZeile1);
  docXml = replaceAll(docXml, 'Musterstadt e.', unit.nameZeile2);
  docXml = replaceAll(docXml, 'Zusatz/Abteilung', unit.zusatz);
  docXml = replaceAll(docXml, '000 123456-0', unit.tel);
  docXml = replaceAll(docXml, '000 123456-11', unit.fax);
  docXml = replaceAll(docXml, 'muster@drk-muster.de', unit.email);
  docXml = replaceAll(docXml, 'www.drk-muster.de', unit.web);
  docXml = replaceAll(docXml, 'Präsident/in', unit.praesidentLabel);
  docXml = replaceAll(docXml, 'Vorsitzende/r des Vorstands', unit.vorsitzenderLabel);
  docXml = replaceAll(docXml, 'Amtsgericht Musterstadt', unit.amtsgericht);
  docXml = replaceAll(docXml, 'Vereinsregister-Nr. VR 0000', unit.vrNummer);
  docXml = replaceAll(docXml, 'DE 000000000', unit.ustId);
  docXml = replaceAll(docXml, 'Muster Bank A', unit.bankName);
  docXml = replaceAll(docXml, 'DE00 0000 0000 0000 0000 00', unit.bankIban);
  docXml = replaceAll(docXml, '000000 00 000', unit.bankBic);

  // MA-Daten
  docXml = replaceAll(docXml, 'Martin Muster', ma.name);
  docXml = replaceAll(docXml, 'Funktion', ma.funktion);
  docXml = replaceAll(docXml, 'Abteilung', ma.abteilung);

  // Brief-Daten
  docXml = replaceAll(docXml, 'Musterfirma', brief.empfaengerFirma);
  docXml = replaceAll(docXml, 'Max Mustermann', brief.empfaengerName);

  // replaceFirst 2x: Adresse (erst Empfänger, dann Absender)
  docXml = replaceFirst(docXml, 'Musterstraße 12', brief.empfaengerStrasse);
  docXml = replaceFirst(docXml, 'Musterstraße 12', unit.strasse);
  docXml = replaceFirst(docXml, '12345 Musterstadt', brief.empfaengerPlzOrt);
  docXml = replaceFirst(docXml, '12345 Musterstadt', unit.plzOrt);

  // Vorname Name: erst Präsident, dann Vorsitzender
  docXml = replaceFirst(docXml, 'Vorname Name', unit.praesidentName);
  docXml = replaceFirst(docXml, 'Vorname Name', unit.vorsitzenderName);

  // Ort + Datum
  docXml = replaceAll(docXml, 'Musterstadt, den 00.00.0000', `${unit.ort}, den ${brief.datum}`);

  // Anrede + Grußformel
  docXml = replaceAll(docXml, 'Sehr geehrte Damen und Herren,', brief.anrede);
  docXml = replaceAll(docXml, 'Mit freundlichen Grüßen', brief.grussformel);

  // MACROBUTTON-Felder: Betreff
  docXml = docXml.replace(
    /<w:fldChar w:fldCharType="begin"\/>[\s\S]*?MACROBUTTON[\s\S]*?\[Betreff\][\s\S]*?<w:fldChar w:fldCharType="end"\/>/,
    `<w:t>${escXml(brief.betreff)}</w:t>`
  );

  // MACROBUTTON-Felder: Text
  docXml = docXml.replace(
    /<w:fldChar w:fldCharType="begin"\/>[\s\S]*?MACROBUTTON[\s\S]*?\[Text\][\s\S]*?<w:fldChar w:fldCharType="end"\/>/,
    textToRuns(brief.text)
  );

  zip.file('word/document.xml', docXml);
  const blob = await zip.generateAsync({
    type: 'blob',
    mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  });

  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  const safeName = (brief.betreff || 'Brief').replace(/[^\w\s-]/g, '').trim().slice(0, 40);
  a.download = `DRK-Briefbogen_${safeName}_${brief.datum.replace(/\./g, '-')}.docx`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}
